// === ตรวจสอบ input mode + เตรียมข้อมูล + detect file type ===
const item = $input.item;
const body = (item.json && item.json.body) ? item.json.body : (item.json || {});

let binaryKey = null;
if (item.binary && Object.keys(item.binary).length > 0) {
  binaryKey = Object.keys(item.binary)[0];
}

let mode, url, originalFileName;

if (binaryKey) {
  mode = 'file';
  url = null;
  originalFileName = item.binary[binaryKey].fileName || 'upload.pdf';
} else if (body.url) {
  mode = 'url';
  url = body.url;
  originalFileName = body.filename || url.split('/').pop().split('?')[0] || 'from_url';
} else {
  throw new Error('ต้องส่งไฟล์ (multipart/form-data) หรือ URL ใน JSON body { "url": "https://..." }');
}

// === Detect file extension + category ===
const lastDot = originalFileName.lastIndexOf('.');
let ext = lastDot > 0 ? originalFileName.substring(lastDot + 1).toLowerCase() : '';

// ถ้าไม่มี extension จาก filename → guess จาก URL pattern
if (!ext && url) {
  if (url.match(/\.(pdf|docx?|pptx?|xlsx?|html?|txt|md|jpg|jpeg|png|tif|tiff|bmp|webp)(\?|$)/i)) {
    ext = url.match(/\.([a-z0-9]+)(\?|$)/i)[1].toLowerCase();
  }
}

// แบ่ง category
const IMAGE_EXT = ['jpg', 'jpeg', 'png', 'tif', 'tiff', 'bmp', 'webp', 'ppm', 'pnm'];
const OFFICE_EXT = ['docx', 'doc', 'pptx', 'ppt', 'xlsx', 'xls'];
const WEB_EXT = ['html', 'htm', 'xhtml'];
const TEXT_EXT = ['txt', 'md', 'markdown', 'csv'];

let category;
if (ext === 'pdf') category = 'pdf';
else if (IMAGE_EXT.includes(ext)) category = 'image';
else if (OFFICE_EXT.includes(ext)) category = 'office';
else if (WEB_EXT.includes(ext)) category = 'web';
else if (TEXT_EXT.includes(ext)) category = 'text';
else category = 'unknown';

const ocrAble = (category === 'pdf' || category === 'image');

// === Sanitize filename ===
const isAsciiOnly = /^[\x00-\x7F]*$/.test(originalFileName);
const hasSpecialChars = /[\s'"\\\/&?#%]/.test(originalFileName);
const needRename = !isAsciiOnly || hasSpecialChars || !ext;

let safeFileName;
if (needRename) {
  const timestamp = Date.now();
  const random = Math.random().toString(36).substring(2, 10);
  const safeExt = ext || 'pdf';
  safeFileName = `doc_${timestamp}_${random}.${safeExt}`;
} else {
  safeFileName = originalFileName;
}

console.log(`📥 Input: mode=${mode}, ext=${ext}, category=${category}, ocr-able=${ocrAble}`);
console.log(`   original=${originalFileName}, safe=${safeFileName}`);

const output = {
  json: {
    mode, url,
    original_filename: originalFileName,
    safe_filename: safeFileName,
    file_extension: ext,
    file_category: category,
    ocr_able: ocrAble,
    was_renamed: needRename,
    uploaded_at: new Date().toISOString()
  }
};

if (binaryKey) {
  const srcBinary = item.binary[binaryKey];
  srcBinary.fileName = safeFileName;
  output.binary = { data0: srcBinary };
}

return output;

// === Normalize binary หลัง URL download + redetect file type จาก mime ===
const item = $input.item;
const sourceKey = Object.keys(item.binary || {})[0];
if (!sourceKey) throw new Error('ไม่พบ binary หลัง download URL');

const meta = $('ตรวจสอบ Input Mode').item.json;
const srcBinary = item.binary[sourceKey];

// === Redetect category จาก mime type (สำคัญ! URL อาจไม่บอก extension จริง) ===
const mime = (srcBinary.mimeType || '').toLowerCase();
let redetectedCategory = meta.file_category;
let redetectedExt = meta.file_extension;

if (mime.includes('pdf')) { redetectedCategory = 'pdf'; redetectedExt = 'pdf'; }
else if (mime.startsWith('image/')) {
  redetectedCategory = 'image';
  redetectedExt = mime.split('/')[1].split(';')[0];
  if (redetectedExt === 'jpeg') redetectedExt = 'jpg';
}
else if (mime.includes('html')) { redetectedCategory = 'web'; redetectedExt = 'html'; }
else if (mime.includes('wordprocessingml') || mime.includes('msword')) { redetectedCategory = 'office'; redetectedExt = 'docx'; }
else if (mime.includes('presentationml')) { redetectedCategory = 'office'; redetectedExt = 'pptx'; }
else if (mime.includes('spreadsheetml') || mime.includes('ms-excel')) { redetectedCategory = 'office'; redetectedExt = 'xlsx'; }
else if (mime.includes('text/plain') || mime.includes('text/markdown')) { redetectedCategory = 'text'; redetectedExt = mime.includes('markdown') ? 'md' : 'txt'; }

// ถ้า extension เดิม unknown แต่ตรวจเจอจาก mime → ใช้ใหม่
if (meta.file_category === 'unknown' && redetectedCategory !== 'unknown') {
  console.log(`🔍 Redetected from mime: ${meta.file_extension} → ${redetectedExt} (${redetectedCategory})`);
  meta.file_extension = redetectedExt;
  meta.file_category = redetectedCategory;
  meta.ocr_able = (redetectedCategory === 'pdf' || redetectedCategory === 'image');
  // อัพเดท safe_filename ให้มี extension ใหม่
  const base = meta.safe_filename.replace(/\.[^.]+$/, '');
  meta.safe_filename = `${base}.${redetectedExt}`;
}

srcBinary.fileName = meta.safe_filename;

console.log(`📦 URL binary: key=${sourceKey}, size=${srcBinary.fileSize}, mime=${mime}, category=${meta.file_category}`);

return {
  json: meta,
  binary: { data0: srcBinary }
};

// === ดึง binary จาก path ก่อนหน้า เพื่อส่งต่อให้ OCRmyPDF ===
const urlMode = $('ตรวจสอบ Input Mode').item.json.mode === 'url';

let sourceItem;
if (urlMode) {
  sourceItem = $('Normalize Binary (URL)').item;
} else {
  sourceItem = $('ตรวจสอบ Input Mode').item;
}

if (!sourceItem.binary || !sourceItem.binary.data0) {
  throw new Error('ไม่พบ binary data0 จากต้นทาง');
}

const meta = $('ตรวจสอบ Input Mode').item.json;
const srcBinary = sourceItem.binary.data0;
console.log(`⚠️  text สั้น (${$input.item.json.text_length} chars), ${meta.file_category} → ส่งไป OCR | size=${srcBinary.fileSize}`);

return {
  json: meta,
  binary: { data0: srcBinary }
};

// === ใช้ binary จาก OCRmyPDF ตรง ๆ ===
const item = $input.item;
const keys = Object.keys(item.binary || {});
if (keys.length === 0) throw new Error('ไม่พบ binary หลัง OCRmyPDF');

let sourceKey = keys[0];
let maxSize = item.binary[sourceKey].fileSize || 0;
for (const k of keys) {
  const size = item.binary[k].fileSize || 0;
  if (size > maxSize) {
    sourceKey = k;
    maxSize = size;
  }
}

const ocrBinary = item.binary[sourceKey];
console.log(`📦 OCR binary: key=${sourceKey}, size=${ocrBinary.fileSize}, name=${ocrBinary.fileName}`);

return {
  json: $('ตรวจสอบ Input Mode').item.json,
  binary: { data0: ocrBinary }
};

