// === รวม chunk + context + metadata ===
const contextSummary = ($input.item.json.text || $input.item.json.output || '').trim();
const chunkData = $('Loop Over Chunks').item.json;
const chunk = chunkData.chunk_text;
const chunkIdx = chunkData.chunk_index;
const chunkTotal = chunkData.chunk_total;
const docMeta = chunkData.doc_meta || {};

console.log(`🔗 chunk #${chunkIdx}/${chunkTotal - 1} (${chunk.length} chars + ctx ${contextSummary.length})`);

const enrichedText = contextSummary
  ? `[บริบท]\n${contextSummary}\n\n[เนื้อหา]\n${chunk}`
  : chunk;

return {
  json: {
    text: enrichedText,
    filename: chunkData.original_filename,
    safe_filename: chunkData.safe_filename,
    file_category: chunkData.file_category || 'unknown',
    doc_type: docMeta.doc_type || 'อื่นๆ',
    department: docMeta.department || 'ไม่ระบุ',
    faculty: docMeta.faculty || 'ไม่ระบุ',
    topic: docMeta.topic || '',
    doc_summary: docMeta.doc_summary || '',
    academic_year: docMeta.academic_year || 'ไม่ระบุ',
    budget_year: docMeta.budget_year || 'ไม่ระบุ',
    target_audience: docMeta.target_audience || 'ไม่ระบุ',
    language: docMeta.language || 'ไทย',
    keywords: Array.isArray(docMeta.keywords) ? docMeta.keywords : [],
    keywords_string: Array.isArray(docMeta.keywords) ? docMeta.keywords.join(',') : '',
    chunk_index: chunkIdx,
    chunk_total: chunkTotal,
    chunk_text: chunk,
    chunk_context: contextSummary,
    chunk_char_count: chunk.length,
    ingested_at: chunkData.ingested_at
  }
};

