// === แบ่งข้อความเป็น chunk + เตรียม metadata ระดับเอกสาร ===
let rawText, originalFilename, safeFilename, fileCategory;
try {
  rawText = $('Normalize Text 2').item.json.text;
  if (!rawText || rawText.length < 200) throw new Error('use text 1');
  originalFilename = $('Normalize Text 2').item.json.original_filename;
  safeFilename = $('Normalize Text 2').item.json.safe_filename;
  fileCategory = $('Normalize Text 2').item.json.file_category;
  console.log('📄 ใช้ text จาก path 2 (OCR)');
} catch (e) {
  rawText = $('Normalize Text 1').item.json.text;
  originalFilename = $('Normalize Text 1').item.json.original_filename;
  safeFilename = $('Normalize Text 1').item.json.safe_filename;
  fileCategory = $('Normalize Text 1').item.json.file_category;
  console.log('📄 ใช้ text จาก path 1 (direct)');
}

let docMeta = {};
try {
  const llmOut = $input.item.json.text || $input.item.json.output || $input.item.json.response || '{}';
  docMeta = typeof llmOut === 'string' ? JSON.parse(llmOut) : llmOut;
} catch (e) {
  console.log('Parse doc metadata failed:', e.message);
  docMeta = { doc_type: 'อื่นๆ', department: 'ไม่ระบุ', faculty: 'ไม่ระบุ', keywords: [] };
}

function splitText(text, size = 1200, overlap = 200) {
  if (!text || text.length <= size) return [text || ''];
  const separators = ['\n\n', '\n', '. ', ' '];
  function split(t, sepIdx) {
    if (t.length <= size) return [t];
    if (sepIdx >= separators.length) {
      const out = [];
      const step = Math.max(1, size - overlap);
      for (let i = 0; i < t.length; i += step) out.push(t.substring(i, i + size));
      return out;
    }
    const sep = separators[sepIdx];
    const parts = t.split(sep);
    const chunks = [];
    let current = '';
    for (const p of parts) {
      const joined = current ? current + sep + p : p;
      if (joined.length > size && current) { chunks.push(current); current = p; }
      else current = joined;
    }
    if (current) chunks.push(current);
    const final = [];
    for (const c of chunks) {
      if (c.length > size) final.push(...split(c, sepIdx + 1));
      else final.push(c);
    }
    return final;
  }
  let chunks = split(text, 0);
  if (overlap > 0 && chunks.length > 1) {
    const out = [chunks[0]];
    for (let i = 1; i < chunks.length; i++) {
      const prev = chunks[i - 1];
      const tail = prev.substring(Math.max(0, prev.length - overlap));
      out.push(tail + chunks[i]);
    }
    chunks = out;
  }
  return chunks;
}

const chunks = splitText(rawText, 1200, 200);
const docSummaryForContext = docMeta.doc_summary || rawText.substring(0, 1500);
console.log(`✂️ แบ่งเอกสาร "${originalFilename}" (${fileCategory}) → ${chunks.length} chunks (${rawText.length} chars)`);

return chunks.map((chunkText, idx) => ({
  json: {
    chunk_text: chunkText,
    chunk_index: idx,
    chunk_total: chunks.length,
    doc_summary_for_context: docSummaryForContext,
    original_filename: originalFilename,
    safe_filename: safeFilename,
    file_category: fileCategory,
    doc_meta: docMeta,
    ingested_at: new Date().toISOString()
  }
}));
